const prisma = require('../config/prisma');

function buildTaskScope(user) {
  if (user.role === 'ADMIN') {
    return {};
  }

  return {
    OR: [
      { assignedToId: user.id },
      {
        project: {
          members: {
            some: { userId: user.id }
          }
        }
      }
    ]
  };
}

function buildProjectScope(user) {
  if (user.role === 'ADMIN') {
    return {};
  }

  return {
    members: {
      some: { userId: user.id }
    }
  };
}

function aggregateBy(items, field) {
  return items.reduce((accumulator, item) => {
    const key = item[field];
    accumulator[key] = (accumulator[key] || 0) + 1;
    return accumulator;
  }, {});
}

async function getDashboardSummary(user) {
  const projectWhere = buildProjectScope(user);
  const taskWhere = buildTaskScope(user);
  const scopedProjectIds =
    user.role === 'ADMIN'
      ? []
      : (
          await prisma.project.findMany({
            where: projectWhere,
            select: { id: true }
          })
        ).map((project) => project.id);
  const scopedTaskIds =
    user.role === 'ADMIN'
      ? []
      : (
          await prisma.task.findMany({
            where: taskWhere,
            select: { id: true }
          })
        ).map((task) => task.id);

  const [projectsCount, tasks, activities, users] = await Promise.all([
    prisma.project.count({ where: projectWhere }),
    prisma.task.findMany({
      where: taskWhere,
      select: {
        id: true,
        status: true,
        priority: true,
        dueDate: true,
        completedAt: true,
        assignedToId: true,
        assignee: {
          select: {
            id: true,
            name: true
          }
        }
      }
    }),
    prisma.activityLog.findMany({
      where:
        user.role === 'ADMIN'
          ? {}
          : {
              OR: [
                { actorId: user.id },
                { projectId: { in: scopedProjectIds } },
                { taskId: { in: scopedTaskIds } }
              ]
            },
      include: {
        actor: {
          select: {
            id: true,
            name: true,
            avatar: true,
            role: true
          }
        }
      },
      orderBy: {
        createdAt: 'desc'
      },
      take: 10
    }),
    prisma.user.findMany({
      select: {
        id: true,
        name: true,
        avatar: true
      }
    })
  ]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((task) => task.status === 'COMPLETED').length;
  const pendingTasks = tasks.filter((task) => ['TODO', 'IN_PROGRESS'].includes(task.status)).length;
  const overdueTasks = tasks.filter(
    (task) =>
      task.status === 'OVERDUE' ||
      (task.dueDate && task.dueDate < new Date() && task.status !== 'COMPLETED')
  ).length;
  const productivity = totalTasks ? Math.round((completedTasks / totalTasks) * 100) : 0;

  const statusBreakdown = aggregateBy(tasks, 'status');
  const priorityBreakdown = aggregateBy(tasks, 'priority');

  const performanceByUser = tasks.reduce((accumulator, task) => {
    if (!task.assignee) {
      return accumulator;
    }

    const existing = accumulator[task.assignee.id] || {
      userId: task.assignee.id,
      name: task.assignee.name,
      completed: 0,
      total: 0
    };

    existing.total += 1;
    if (task.status === 'COMPLETED') {
      existing.completed += 1;
    }

    accumulator[task.assignee.id] = existing;
    return accumulator;
  }, {});

  const userPerformance = Object.values(performanceByUser)
    .map((entry) => ({
      ...entry,
      completionRate: entry.total ? Math.round((entry.completed / entry.total) * 100) : 0
    }))
    .sort((left, right) => right.completionRate - left.completionRate)
    .slice(0, 6);

  const completionTrend = Array.from({ length: 7 }).map((_, index) => {
    const day = new Date();
    day.setHours(0, 0, 0, 0);
    day.setDate(day.getDate() - (6 - index));
    const label = day.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    const completed = tasks.filter((task) => {
      if (!task.completedAt) {
        return false;
      }

      const completedAt = new Date(task.completedAt);
      completedAt.setHours(0, 0, 0, 0);
      return completedAt.getTime() === day.getTime();
    }).length;

    return {
      label,
      completed
    };
  });

  return {
    summary: {
      totalProjects: projectsCount,
      totalTasks,
      completedTasks,
      pendingTasks,
      overdueTasks,
      teamProductivity: productivity
    },
    charts: {
      statusBreakdown,
      priorityBreakdown,
      completionTrend
    },
    recentActivity: activities,
    userPerformance,
    teamSize: users.length
  };
}

module.exports = {
  getDashboardSummary
};
